import heapq
from collections import defaultdict

class Solution(object):
    def minTime(self, n, edges):
        adj = defaultdict(list)
        for u, v, s, e in edges:
            adj[u].append((v, s, e))

        dist = [float('inf')] * n
        dist[0] = 0
        heap = [(0, 0)]  # (time, node)

        while heap:
            t, u = heapq.heappop(heap)
            if t > dist[u]:
                continue
            if u == n - 1:
                return t
            for v, s, e in adj[u]:
                if t > e:
                    continue  # missed the window
                arrive = max(t, s) + 1  # wait if needed, then traverse
                if arrive < dist[v]:
                    dist[v] = arrive
                    heapq.heappush(heap, (arrive, v))

        return -1
